def pagerank(graph, damping_factor=0.85, iterations=100):
    all_pages = set()
    for page, links in graph.items():
        all_pages.add(page)
        for link in links:
            all_pages.add(link)

    N = len(all_pages)

    pageranks = {page: 1.0 / N for page in all_pages}

    out_degrees = {page: len(links) for page, links in graph.items()}
    for page in all_pages:
        if page not in out_degrees:
            out_degrees[page] = 0

    for _ in range(iterations):
        new_pageranks = {page: 0.0 for page in all_pages}

        dangling_sum = 0.0
        for page in all_pages:
            if out_degrees[page] == 0:
                dangling_sum += pageranks[page]

        for page in all_pages:
            new_pageranks[page] = (1 - damping_factor) / N + damping_factor * dangling_sum / N

        for referrer_page, links_from_referrer in graph.items():
            if out_degrees[referrer_page] > 0:
                rank_contribution = pageranks[referrer_page] / out_degrees[referrer_page]
                for target_page in links_from_referrer:
                    new_pageranks[target_page] += damping_factor * rank_contribution

        pageranks = new_pageranks

    return pageranks
